<template>
  <el-table v-loading="loading" element-loading-text="玩命加载中" element-loading-background="rgba(255, 255, 255, 1)" :data="tbodyData" height="'100%'" size="mini" show-summary>
    <el-table-column v-for="col in theadData" :key="col.label" :label="col.label" :prop="col.prop" :width="col.width" :fixed="col.fixed" :formatter="col.formatter" />
  </el-table>
</template>
<script>
import Service from '@/service.js';

const columns = [{
  label: '姓名',
  width: 200,
  fixed: 'left',
  formatter: row => `${row.name.first} ${row.name.last}`
}, {
  label: '账号',
  prop: 'login.username',
  width: 200
}, {
  label: '性别',
  prop: 'gender',
  width: 100
}, {
  label: '年龄',
  prop: 'dob.age',
  width: 100
}, {
  label: '生日',
  prop: 'dob.date',
  width: 200
}, {
  label: '电话',
  prop: 'phone',
  width: 200
}, {
  label: '邮箱',
  prop: 'email',
  width: 300
}, {
  label: '住址',
  prop: 'location.street',
  width: 300
}, {
  label: 'MD5',
  prop: 'login.md5',
  width: 300
}, {
  label: 'SHA1',
  prop: 'login.sha1',
  width: 300
}];

export default {
  data() {
    return {
      theadData: [],
      tbodyData: [],
      loading: true
    }
  },
  mounted() {
    Service.getRandomUser(500, 'ch').then(response => {
      this.theadData = columns;
      this.tbodyData = response.data.results;
      this.loading = false;
    });
  }
}
</script>